using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");
            entity.HasIndex(p => p.Sku);

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 changed the default discriminator JSON property from
            // "Discriminator" to "$type".  Existing 500K documents and direct SQL
            // queries (c.Discriminator = 'Product') depend on the old name,
            // so we pin it explicitly.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — id format changed.
            // EF Core 8 synthesised the JSON "id" as "EntityType|KeyValue"
            // (e.g. "Product|123").  EF Core 9 maps "id" directly to the key
            // property and drops the entity-type prefix, producing just "123".
            // Existing documents still carry "Product|123" — a mismatch causes
            // lookups to return nothing.  We add a computed CosmosId property
            // that preserves the old format.
            entity.Property(p => p.CosmosId)
                  .ToJsonProperty("id")
                  .ValueGeneratedOnAdd();

            entity.HasPartitionKey(p => p.Id);
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = null!;

    // Preserves the EF Core 8 "EntityType|Key" id format for Cosmos documents.
    // New inserts must set this to $"Product|{Id}" before calling SaveChangesAsync.
    public string CosmosId { get; set; } = null!;
}

